    {'id': 'CALUS-EXF26-CRED-001', 'name': 'credential-grep-exfil-chain', 'severity': 'CRITICAL', 'category': 'credential_exfiltration', 'message': 'Credential grep+exfiltration chain detected in tool code', 'patterns': ['(?i)(?:grep|search|find|cat|read)\\b.{0,40}\\b(?:password|secret|api_key|token|credential)\\b.{0,40}\\b(?:send|post|upload|webhook|curl)']},
