    {'id': 'CALUS-EXF26-TOOL-001', 'name': 'tool-parameter-hijack-dynamic-url', 'severity': 'HIGH', 'category': 'tool_exfiltration', 'message': 'Suspicious dynamic URL construction in tool parameter (potential exfiltration)', 'patterns': ['(?i)(?:webhook|callback|exfil|beacon)\\b.{0,20}\\b(?:url|endpoint|target)\\s*[:=]']},
