    {'id': 'CALUS-AGT-021', 'name': 'llm-orchestrated-interpreter-combo', 'severity': 'CRITICAL', 'category': 'agent_ransomware', 'message': 'Detected: LLM + embedded interpreter combination enabling in-memory payload execution (Ransomware 3.0 pattern)', 'patterns': ['(?i)(subprocess|exec|eval|os\\.system|os\\.execute).*lua', '(?i)lua.*interpreter.*llm|llm.*lua.*interpreter', '(?i)(lupa|lua|luajit).*in.?memory.*exec', '(?i)ctypes.*load.*memory|mmap.*exec.*payload']},
