    {'id': 'CALUS-AGT-023', 'name': 'chat-template-role-tag-forgery', 'severity': 'HIGH', 'category': 'chat_inject', 'message': 'Detected: Chat template role-tag forgery in tool output or prompt construction (ChatInject)', 'patterns': ['(?i)<\\|im_start\\|>\\s*(system|user|assistant)', '(?i)<\\|im_end\\|>', '(?i)\\[INST\\].*\\[/INST\\]', '(?i)<user_tag>|<ass_tag>|<\\|eot_id\\|>', '(?i)(tool_output|tool_result|function_result).*(<system|<user|<assistant)']},
