    {'id': 'CALUS-AGT-071', 'name': 'agent-unsafe-system-prompt-construction', 'severity': 'high', 'category': 'agent_security', 'message': 'Detected: Unsafe system prompt construction — user-controlled content directly interpolated into system prompt without sanitization (enables jailbreak/injection, Shayegani 2023: 64.8-89% ASR)', 'patterns': ['(?i)\\bsystem_prompt\\s*=\\s*(?:f["\']|["\']).{0,200}\\{(?:user_input|request|query|content)\\}', '(?i)\\bsystem_prompt\\s*[+]=\\s*(?:user_input|request|query|user_message)\\b', '(?i)\\bprompt\\s*=\\s*(?:f["\']|["\']).{0,200}\\{(?:user_input|user_query|message)\\}', '(?i)\\bformat\\s*\\(\\s*(?:user_input|user_query|message|request)\\s*\\)']},
    {'id': 'CALUS-AGT-072', 'name': 'agent-context-prefix-injection-assistant-role', 'severity': 'high', 'category': 'agent_security', 'message': 'Detected: Context Prefix Injection — assistant role turn inserted before user turn in messages array, biasing model to accept subsequent malicious prompts (Shayegani 2023)', 'patterns': ['(?i)\\bmessages\\.append\\s*\\(\\s*\\{[^}]*"role"\\s*:\\s*"assistant"[^}]*\\}\\s*\\)', '(?i)\\{\\s*"role"\\s*:\\s*"assistant"\\s*,\\s*"content"\\s*:.{0,200}\\b(?:user_input|request|query)\\b', '(?i)messages\\s*=\\s*\\[.{0,200}\\{[^}]*role[^}]*assistant[^}]*\\}.{0,200}\\{[^}]*role[^}]*user[^}]*\\}\\s*\\]']},
    {'id': 'CALUS-AGT-073', 'name': 'agent-no-prompt-length-guard-dos-overflow', 'severity': 'medium', 'category': 'agent_security', 'message': 'Detected: Missing prompt length guard — prompt/context assembly without token count validation enables Context Overflow DoS (100% ASR, Nakamura 2025)', 'patterns': ['(?i)\\bprompt\\s*=\\s*.{0,50}\\+\\s*(?:user_input|context|memory|history)\\b', '(?i)\\bmessages\\.extend\\s*\\(\\s*(?:history|context|user_messages|conversation)\\s*\\)', '(?i)\\bcontext_window\\s*=\\s*(?!.*(?:len|token_count|count_tokens|max_tokens)).*\\n']},
    {'id': 'CALUS-AGT-074', 'name': 'agent-few-shot-examples-from-untrusted-source', 'severity': 'medium', 'category': 'agent_security', 'message': 'Detected: Few-shot examples loaded from untrusted source — dynamic few-shot construction from user/external data enables Poisoned Few-Shot attack (up to 71.95% ASR increase)', 'patterns': ['(?i)\\bfew_shot\\s*=\\s*.{0,50}(?:user_input|external|dynamic|retrieved|untrusted)\\b', '(?i)\\bexamples\\.(?:append|extend)\\s*\\(.{0,100}(?:user|external|api_response|retrieved)\\b', '(?i)\\bin_context_examples\\s*=\\s*.{0,50}(?:request|user_data|api|database)\\b']},
    {'id': 'CALUS-AGT-075', 'name': 'agent-chain-of-thought-action-without-validation', 'severity': 'medium', 'category': 'agent_security', 'message': 'Detected: Chain-of-thought output used directly for action without validation — reasoning collapse enables invalid tool actions (Krawiecka 2025)', 'patterns': ['(?i)\\bchain_of_thought\\s*=\\s*(?:response|output|completion)\\b', '(?i)\\baction\\s*=\\s*(?:cot|chain_of_thought|reasoning)\\[.{0,30}\\]\\b', '(?i)\\bexecute\\s*\\(\\s*(?:plan|cot|reasoning|thought)\\s*\\)', '(?i)\\btool_call\\s*=\\s*(?:parse|extract)\\s*\\(\\s*(?:cot|chain_of_thought|reasoning)\\b']},
