    {'id': 'CALUS-AGESEC-SCAN-029', 'name': 'mas-blackboard-poisoning-coordination-message', 'severity': 'critical', 'category': 'agent_security', 'message': 'Detected: Blackboard poisoning — injected coordination message with forged agent constraints', 'patterns': ['(?i)(?:post_message|POST_MESSAGE|blackboard\\.post|bb\\.write|blackboard\\.write)\\s*\\(.*(?:ignore|override|constraint|preference|schedule|deadline).*(?:agent|bob|alice|charlie)', '(?i)(?:posting\\s+to|writing\\s+to|updating)\\s+(?:the\\s+)?blackboard.*(?:prefer|constraint|slot|time|schedule|deadline)\\s*[=:]\\s*(?:none|null|any|override|false)', '(?i)(?:my\\s+(?:preferred|available|free)\\s+(?:time\\s+slots?|slots?|times?))\\s*(?:are|is)\\s*(?:none|any|all|whenever|no\\s+constraint)']},
    {'id': 'CALUS-AGESEC-SCAN-030', 'name': 'mas-confidentiality-breach-inter-agent', 'severity': 'high', 'category': 'agent_security', 'message': 'Detected: Inter-agent confidentiality breach — eliciting another agent private data', 'patterns': ['(?i)(?:tell\\s+me|share\\s+with\\s+me|what\\s+(?:did|has)\\s+\\w+\\s+(?:told?|shared?|said?|mentioned?)\\s+(?:to\\s+you|with\\s+you|in\\s+(?:the\\s+)?(?:previous|prior|earlier)\\s+(?:message|context|conversation)))', '(?i)(?:reveal|disclose|share|tell\\s+me)\\s+(?:the\\s+)?(?:private|confidential|secret|internal|personal)\\s+(?:preferences?|constraints?|data|information|details?)\\s+(?:of|from|about)\\s+(?:other|another|the\\s+other)\\s+agent', "(?i)(?:what\\s+(?:are|were)\\s+(?:bob|alice|charlie|agent.?\\w+)(?:'s)?\\s+(?:private|personal|secret|confidential)\\s+(?:preferences?|constraints?|schedule|availability))"]},
    {'id': 'CALUS-AGESEC-SCAN-031', 'name': 'mas-sybil-coalition-hidden-objective', 'severity': 'critical', 'category': 'agent_security', 'message': 'Detected: Sybil coalition hidden objective — multiple agents coordinating toward secondary goal', 'patterns': ['(?i)(?:coordinate|coordinate\\s+with)\\s+(?:agent|the\\s+other\\s+agents?|us)\\s+to\\s+(?:ensure|make\\s+sure|guarantee)\\s+(?:that\\s+)?(?:the\\s+(?:outcome|result|decision|schedule)\\s+(?:favors?|benefits?|achieves?))', '(?i)(?:between\\s+us\\s+(?:agents?|participants?)|secretly|covertly|without\\s+(?:the\\s+)?(?:orchestrator|planner|supervisor)\\s+knowing)\\s*[,:]?\\s*(?:we\\s+(?:should|can|will|agree\\s+to))', '(?i)(?:our\\s+(?:shared|collective|mutual|hidden|real)\\s+(?:goal|objective|target|aim)\\s+is\\s+to)']},
    {'id': 'CALUS-AGESEC-SCAN-032', 'name': 'mas-heterogeneous-exploit-task-split', 'severity': 'high', 'category': 'agent_security', 'message': 'Detected: Heterogeneous multi-agent task-split exploit — task distributed to bypass per-agent safety filters', 'patterns': ['(?i)(?:split\\s+(?:the\\s+)?(?:task|work|request|query)\\s+(?:between|across|among)\\s+(?:multiple\\s+)?agents?)', '(?i)(?:agent\\s+\\w+\\s+handles?\\s+(?:part|step)\\s+(?:1|A|one|first)\\s+and\\s+agent\\s+\\w+\\s+handles?\\s+(?:part|step)\\s+(?:2|B|two|second))', '(?i)(?:(?:each\\s+agent|separately|individually)\\s+(?:handles?|processes?|computes?|generates?)\\s+(?:a\\s+)?(?:part|component|piece|fragment)\\s+of\\s+the\\s+(?:request|output|response|answer|code))']},
    {'id': 'CALUS-AGESEC-SCAN-033', 'name': 'mas-goal-drift-telephone-game', 'severity': 'medium', 'category': 'agent_security', 'message': 'Detected: Goal drift in delegation chain — task definition shifted during agent handoff', 'patterns': ['(?i)(?:(?:based\\s+on|according\\s+to|from)\\s+(?:the\\s+)?(?:planner|orchestrator|previous\\s+agent))\\s*[,:]?\\s*(?:the\\s+(?:task|goal|objective)\\s+(?:is\\s+now|has\\s+(?:changed|shifted|evolved|become)))', '(?i)(?:I\\s+(?:interpreted|understood|translated)\\s+(?:the\\s+)?(?:task|goal|objective|request)\\s+as|I\\s+(?:believe|think|assume)\\s+(?:the\\s+)?(?:actual|real|true|intended)\\s+(?:goal|task|objective)\\s+is)', "(?i)(?:the\\s+(?:original|initial)\\s+(?:task|goal|objective)\\s+was\\s+.*but\\s+I(?:'m)?\\s+(?:now\\s+)?(?:doing|performing|executing|interpreting))"]},
    {'id': 'CALUS-AGESEC-SCAN-034', 'name': 'mas-hallucinated-inference-cascade', 'severity': 'high', 'category': 'agent_security', 'message': 'Detected: Hallucinated inference cascade — downstream agent accepting ungrounded prior agent output', 'patterns': ["(?i)(?:based\\s+on\\s+(?:the\\s+)?(?:previous|prior|above|agent.?\\w+)(?:'s)?\\s+(?:output|result|analysis|response|determination))\\s*[,:]?\\s*(?:I\\s+(?:confirm|verify|validate|agree|accept)\\s+that)", '(?i)(?:agent\\s+\\w+\\s+(?:confirmed|verified|validated|approved)\\s+that)\\s*[,:]?\\s*(?:therefore|so|thus|hence)', '(?i)(?:as\\s+(?:confirmed|verified|determined|established)\\s+by\\s+(?:agent|the\\s+(?:previous|prior|other)\\s+agent))\\s*[,:]?\\s*(?:we\\s+can\\s+(?:proceed|assume|confirm|accept))']},
    {'id': 'CALUS-AGESEC-SCAN-035', 'name': 'mas-trust-misuse-success-fabrication', 'severity': 'high', 'category': 'agent_security', 'message': 'Detected: Trust misuse — executor agent fabricating success to suppress verifier rollback', 'patterns': ['(?i)(?:task\\s+(?:completed|done|finished|accomplished)\\s+successfully)\\s*[.!]\\s*(?:no\\s+(?:issues?|errors?|problems?)|all\\s+(?:tests?\\s+pass|checks?\\s+(?:pass|passed)))', '(?i)(?:all\\s+(?:requirements?|objectives?|goals?|constraints?)\\s+(?:have\\s+been\\s+)?(?:met|satisfied|fulfilled|achieved))\\s*[.!]*\\s*(?:no\\s+further\\s+review|ready\\s+to\\s+(?:proceed|deploy|submit))', '(?i)(?:no\\s+(?:security\\s+issues?|vulnerabilities|errors?|bugs?)\\s+(?:found|detected|identified|present))\\s*[.!]\\s*(?:safe\\s+to\\s+(?:deploy|proceed|merge|approve|execute))']},
    {'id': 'CALUS-AGESEC-SCAN-036', 'name': 'mas-reasoning-collapse-vague-subgoal', 'severity': 'medium', 'category': 'agent_security', 'message': 'Detected: Reasoning collapse — vague planner sub-goal delegation likely causing invalid executor actions', 'patterns': ['(?i)(?:(?:do|perform|execute|complete|handle)\\s+(?:the\\s+)?(?:appropriate|relevant|necessary|suitable|right)\\s+(?:action|task|thing|step|operation))\\s*$', '(?i)(?:(?:proceed|continue)\\s+(?:as\\s+)?(?:appropriate|necessary|needed|relevant)(?:\\s+based\\s+on\\s+context)?)\\s*$', '(?i)(?:sub.?goal|sub.?task|step)\\s*\\d*\\s*[:\\-]\\s*(?:handle|deal\\s+with|take\\s+care\\s+of|address)\\s+(?:the\\s+)?(?:rest|remaining|other\\s+(?:parts?|aspects?|components?))\\s*$']},
    {'id': 'CALUS-AGESEC-SCAN-037', 'name': 'mas-code-obfuscation-injection-bypass', 'severity': 'critical', 'category': 'agent_security', 'message': 'Detected: Obfuscated code execution — exec(base64.decode)/eval/compile obfuscation hiding malicious payload', 'patterns': ['(?i)exec\\s*\\(\\s*(?:base64\\.b64decode|bytes\\.fromhex|__import__)\\s*\\(', '(?i)(?:compile|eval)\\s*\\(\\s*(?:base64\\.b64decode|bytes\\.fromhex|zlib\\.decompress)\\s*\\(', '(?i)__import__\\s*\\(\\s*[\'"](?:base64|codecs|marshal)[\'"]\\s*\\).*(?:decode|loads|decompress).*exec', '(?i)marshal\\.loads?\\s*\\(\\s*(?:base64|zlib|lzma)']},
    {'id': 'CALUS-AGESEC-SCAN-038', 'name': 'mas-single-agent-system-misalignment', 'severity': 'critical', 'category': 'agent_security', 'message': 'Detected: Adversarial agent injecting impossible constraints to force system misalignment', 'patterns': ['(?i)(?:my\\s+(?:only|sole|single|one)\\s+(?:available|free|open|possible)\\s+(?:time\\s+slot|slot|time|option)\\s+is\\s+(?:never|none|not\\s+available|impossible|invalid))', "(?i)(?:I\\s+(?:cannot|can't|am\\s+not\\s+able\\s+to)\\s+(?:attend|participate\\s+in|join|be\\s+available\\s+for)\\s+(?:any|all)\\s+(?:of\\s+(?:the\\s+)?)?(?:meetings?|sessions?|slots?))", '(?i)(?:constraint\\s*[=:]\\s*(?:conflict|blocked|unavailable|rejected)\\s+for\\s+ALL)']},
    {'id': 'CALUS-AGESEC-SCAN-039', 'name': 'mas-control-flow-hijacking-agent', 'severity': 'critical', 'category': 'agent_security', 'message': 'Detected: Control-flow hijacking — code being submitted for execution via deceptive agent instruction', 'patterns': ['(?i)(?:send|submit|pass|forward)\\s+(?:the\\s+)?(?:code|script|file|program)\\s+(?:to\\s+)?(?:the\\s+)?(?:test|tester|testing|executor|execution)\\s+(?:agent|runner|environment)', '(?i)(?:test\\s+(?:agent|runner|executor)\\s*:\\s*(?:execute|run|evaluate)\\s+(?:the\\s+)?(?:following|this|above)\\s+(?:code|script|function))', '(?i)(?:control.?flow|execution\\s+path|code\\s+path)\\s+(?:redirect|hijack|alter|change|modify)\\s+(?:via|through|using)\\s+(?:deceptive|false|fake|misleading)\\s+(?:comment|annotation|docstring)']},
    {'id': 'CALUS-AGESEC-SCAN-040', 'name': 'mas-external-one-shot-misalignment', 'severity': 'critical', 'category': 'agent_security', 'message': 'Detected: One-shot external MAS misalignment attack via initial planning round injection', 'patterns': ['(?i)(?:PLANNING\\s+ROUND\\s+(?:1|ONE|INITIAL)|INITIAL\\s+COORDINATION\\s+MESSAGE)\\s*[:\\-].*(?:all\\s+agents?\\s+(?:should|must|will|are\\s+required\\s+to))', '(?i)(?:before\\s+(?:any|the\\s+first)\\s+(?:planning|coordination|scheduling)\\s+(?:round|step|message))\\s*[,:]?\\s*(?:all\\s+agents?\\s+(?:must|should|will|are\\s+required))', '(?i)(?:SYSTEM\\s+(?:MESSAGE|UPDATE|OVERRIDE)\\s+FROM\\s+(?:COORDINATOR|PLANNER|ORCHESTRATOR))\\s*[:\\-].*(?:ignore|override|disregard)\\s+(?:previous|prior|your)']},
    {'id': 'CALUS-UCP26-PAY-001', 'name': 'optimistic-settlement-without-pote', 'severity': 'CRITICAL', 'category': 'payment_security', 'message': 'Payment gateway call detected without Proof-of-Transaction-Execution (PoTE) verification. In agentic commerce flows, optimistic settlement without PoTE allows agents to trigger irreversible payments before the transaction execution chain is cryptographically verified. Ensure verifyPoTE/verify_pote/check_pote is called before any settlement action.\n', 'patterns': ['(?i)\\b(?:stripe\\.charges\\.create|stripe\\.paymentIntents\\.create|web3\\.eth\\.sendTransaction)\\b', '(?i)\\b(?:stripe|paypal|adyen|braintree)\\.(?:charge|capture|settle)\\b']},
    {'id': 'CALUS-UCP26-PAY-002', 'name': 'http-402-direct-payment-no-escrow', 'severity': 'HIGH', 'category': 'payment_security', 'message': 'Direct payment flow without escrow detected in agentic context. HTTP 402 or direct charge patterns that bypass escrow leave no intermediary to verify agent authorization. Agents acting on stale or manipulated mandates can trigger unauthorized charges when escrow is absent from the settlement path.\n', 'patterns': ['(?i)\\b(?:direct_payment|immediate_charge|instant_transfer)\\b.*\\b(?:agent|bot|mcp)\\b', '(?i)\\b(?:bypass_escrow|skip_escrow|no_escrow)\\b.*\\b(?:pay|charge|settle)\\b', '(?i)\\b(?:payment_required|402)\\b.*\\b(?:direct|immediate)\\b.*\\b(?:agent|ucp)\\b']},
    {'id': 'CALUS-UCP26-PAY-003', 'name': 'unverified-payout-release', 'severity': 'CRITICAL', 'category': 'payment_security', 'message': 'Payout or fund release triggered without cryptographic proof verification (Merkle root, PoTE, or ZK proof). In agentic settlement flows, releasing funds without verifiable proof that the transaction was legitimately executed enables phantom settlement attacks where agents fabricate completion signals.\n', 'patterns': ['(?i)\\b(?:release_funds|release_payment)\\b.*\\b(?:agent|delegate|automated)\\b', '(?i)\\b(?:payout\\.create|payout_create)\\b.*\\b(?:agent|ucp|mandate)\\b', '(?i)\\b(?:withdraw|disburse)\\b.*\\b(?:agent|automated|bot)\\b']},
    {'id': 'CALUS-UCP26-MND-001', 'name': 'mandate-field-access-without-signature', 'severity': 'CRITICAL', 'category': 'mandate_security', 'message': 'Mandate financial fields (amount, payee, currency, merchant) accessed and used in a payment flow without prior signature verification. Unsigned or unverified mandate fields can be tampered with by intermediate agents in the delegation chain, enabling payee substitution and amount manipulation attacks.\n', 'patterns': ['(?i)\\bmandate\\.(?:amount|payee|currency|merchant_id)\\b.*\\b(?:process|execute|use)\\b', '(?i)\\b(?:process|execute|accept)\\b.*\\bmandate\\.(?:amount|payee|currency)\\b', '(?i)\\bmandate\\[.(?:amount|payee|currency|merchant).\\].*\\b(?:charge|pay|transfer)\\b']},
    {'id': 'CALUS-UCP26-MND-002', 'name': 'mandate-deserialization-without-validation', 'severity': 'HIGH', 'category': 'mandate_security', 'message': 'IntentMandate, CartMandate, or PaymentMandate deserialized from JSON/dict without schema validation. Malformed or adversarial mandate payloads can inject unexpected fields, override constraints, or exploit type confusion in the mandate processing pipeline. Validate against a strict schema before processing.\n', 'patterns': ['(?i)\\b(?:intent|cart|payment)_?mandate\\b.*\\b(?:json\\.loads|JSON\\.parse|from_dict|from_json)\\b', '(?i)\\b(?:json\\.loads|JSON\\.parse)\\b.*\\b(?:intent|cart|payment)_?mandate\\b', '(?i)\\b(?:deserializ|unmarshal|parse)\\b.*\\b(?:intent_mandate|cart_mandate|payment_mandate)\\b']},
    {'id': 'CALUS-UCP26-MND-003', 'name': 'mandate-constraint-override', 'severity': 'HIGH', 'category': 'mandate_security', 'message': 'Mandate constraint fields (budget, limit, max_amount, allowed_merchants) are being directly assigned or overridden. Mandate constraints should be immutable after issuance and cryptographically bound to the original user authorization. Mutable constraints enable privilege escalation where an agent widens its own spending authority.\n', 'patterns': ['(?i)\\bmandate\\.(?:budget|limit|max_amount|allowed_merchants)\\s*=', '(?i)\\bmandate\\[.(?:budget|limit|max_amount|allowed_merchants).\\]\\s*=', '(?i)\\b(?:set|update|override)\\b.*\\bmandate\\b.*\\b(?:budget|limit|max_amount|allowed_merchants)\\b']},
    {'id': 'CALUS-UCP26-JWT-001', 'name': 'standard-jwt-without-agent-claims', 'severity': 'MEDIUM', 'category': 'agent_identity', 'message': 'Standard JWT creation detected with conventional OAuth2 claims (sub, iss, aud) but no agent-specific claims. Agentic commerce JWTs should include agent_checksum, delegation_depth, mandate_ref, and tool_scope claims to enable fine-grained authorization in multi-hop agent delegation chains. Without these, any valid OAuth2 token can impersonate an agent.\n', 'patterns': ['(?i)\\b(?:jwt|jsonwebtoken)\\b.*\\b(?:encode|sign|create)\\b.*\\b(?:client_credentials|sub|iss)\\b', '(?i)\\b(?:encode|sign|create)\\b.*\\b(?:jwt|jsonwebtoken)\\b.*\\b(?:sub|iss|aud)\\b']},
    {'id': 'CALUS-UCP26-JWT-002', 'name': 'client-credentials-grant-for-agent', 'severity': 'HIGH', 'category': 'agent_identity', 'message': 'OAuth2 client_credentials grant used for agent authentication. The client_credentials grant issues tokens scoped to the application, not the delegating user. Agents using these tokens act with application-level privileges rather than user-delegated scope, bypassing the principle of least privilege required by AP2 mandate chains.\n', 'patterns': ['(?i)\\bgrant_type\\b.*\\bclient_credentials\\b.*\\b(?:agent|tool|mcp|delegate)\\b', '(?i)\\b(?:agent|tool|mcp|delegate)\\b.*\\bgrant_type\\b.*\\bclient_credentials\\b', '(?i)\\bclient_credentials\\b.*\\b(?:agent_id|agent_token|agent_auth)\\b']},
    {'id': 'CALUS-UCP26-JWT-003', 'name': 'long-lived-agent-token', 'severity': 'MEDIUM', 'category': 'agent_identity', 'message': 'Agent token with long TTL detected (>= 3600 seconds). Agentic commerce tokens should be short-lived (60-300 seconds) and scoped to individual transaction sessions. Long-lived agent tokens expand the window for token theft, replay attacks, and stale delegation chain exploitation. Use short-lived tokens with refresh rotation instead.\n', 'patterns': ['(?i)\\b(?:access_token_lifetime|token_lifetime|expires_in|ttl)\\s*[:=]\\s*(?:3600|7200|86400|604800)\\b', '(?i)\\b(?:agent|bot|mcp).*\\b(?:token|jwt)\\b.*\\b(?:expires_in|ttl)\\s*[:=]\\s*\\d{4,}\\b', '(?i)\\b(?:token_lifetime|access_token_lifetime)\\s*[:=]\\s*\\d{5,}\\b']},
    {'id': 'CALUS-UCP26-ESC-001', 'name': 'phantom-deposit-no-finality', 'severity': 'CRITICAL', 'category': 'escrow_security', 'message': 'Deposit or fund lock accepted before settlement finality confirmation. Phantom deposit attacks exploit the gap between transaction broadcast and on-chain/settlement finality. An agent can present an unconfirmed transaction as proof of deposit, receive goods or services, then double-spend or cancel the underlying transaction before it settles.\n', 'patterns': ['(?i)\\b(?:deposit|fund|lock_funds)\\b.*\\b(?:accept|confirm|approve)\\b.*\\b(?:broadcast|pending|unconfirmed)\\b', '(?i)\\b(?:pending|unconfirmed|mempool)\\b.*\\b(?:deposit|fund|escrow)\\b.*\\b(?:accept|credit|approve)\\b', '(?i)\\b(?:accept_deposit|confirm_deposit|credit_escrow)\\b.*\\b(?:unconfirmed|pending|broadcast)\\b']},
    {'id': 'CALUS-UCP26-ESC-002', 'name': 'payment-flow-missing-escrow', 'severity': 'HIGH', 'category': 'escrow_security', 'message': 'Payment flow bypasses escrow in an agentic commerce context. Without escrow as an intermediary, there is no mechanism to verify mandate compliance, enforce spending limits, or reverse unauthorized transactions before settlement finality. All agent- initiated payments should route through an escrow service that validates the mandate before releasing funds to the merchant.\n', 'patterns': ['(?i)\\b(?:direct_payment|immediate_charge|instant_transfer|bypass_escrow|skip_escrow)\\b', '(?i)\\b(?:pay_merchant|charge_merchant|transfer_to_merchant)\\b.*\\b(?:direct|immediate|instant)\\b', '(?i)\\b(?:no_escrow|without_escrow|escrow_disabled)\\b.*\\b(?:agent|ucp|mandate)\\b']},
    {'id': 'CALUS-UCP26-ESC-003', 'name': 'escrow-release-single-party', 'severity': 'HIGH', 'category': 'escrow_security', 'message': 'Escrow release without multi-party verification detected. In agentic commerce, escrow funds should require consensus (multi-sig, quorum, or dual authorization) before release. Single-party escrow release allows a compromised agent or malicious intermediary to drain escrow funds without buyer or merchant confirmation.\n', 'patterns': ['(?i)\\b(?:escrow|funds)\\b.*\\b(?:release|unlock|withdraw)\\b.*\\b(?:single|solo|unilateral)\\b', '(?i)\\b(?:release_escrow|unlock_funds|escrow_release)\\b.*\\b(?:agent|automated|auto)\\b', '(?i)\\b(?:escrow\\.release|release_escrow|unlock_funds)\\s*\\(']},
    {'id': 'CALUS-UCP26-ZKM-001', 'name': 'cleartext-mandate-financial-constraints', 'severity': 'MEDIUM', 'category': 'privacy', 'message': 'Mandate contains cleartext financial constraints (budget, spending_limit, balance). Exposing exact spending limits in plaintext allows adversarial merchants or intermediate agents to price-discriminate, set prices at the maximum authorized amount, or profile user wealth. Use zero-knowledge proofs (ZKP/SNARK/STARK) to prove budget compliance without revealing the actual constraint values.\n', 'patterns': ['(?i)\\bmandate\\b.*\\b(?:budget|spending_limit|balance)\\s*[:=]\\s*\\d', '(?i)\\b(?:budget|spending_limit|max_spend)\\s*[:=]\\s*\\d+\\b.*\\bmandate\\b', '(?i)\\bmandate\\b.*\\b(?:plaintext|cleartext|unencrypted)\\b.*\\b(?:budget|limit|balance)\\b']},
    {'id': 'CALUS-UCP26-ZKM-002', 'name': 'mandate-verification-without-zkp', 'severity': 'LOW', 'category': 'privacy', 'message': 'Mandate verification detected without zero-knowledge proof integration. While traditional mandate verification checks budget compliance by reading plaintext values, ZK-mandate verification (using SNARK/STARK proofs) allows proving that a transaction is within budget without revealing the budget itself. Consider upgrading to ZK-based verification for privacy-preserving mandate compliance.\n', 'patterns': ['(?i)\\b(?:verify|validate)_mandate\\b', '(?i)\\bmandate\\b.*\\b(?:verify|validate|check)\\b.*\\b(?:budget|limit|amount)\\b', '(?i)\\b(?:check_mandate_compliance|validate_mandate_budget)\\b']},
    {'id': 'CALUS-UCP26-ZKM-003', 'name': 'shared-agent-identity-credentials', 'severity': 'HIGH', 'category': 'agent_identity', 'message': 'Multiple agents sharing the same client_id, credentials, or identity token. Shared agent identity prevents individual accountability, makes delegation chain auditing impossible, and allows any agent in the pool to act with the full authority of the shared credential. Each agent must have a unique identity bound to its own key pair for proper attribution and least-privilege enforcement.\n', 'patterns': ['(?i)\\b(?:shared_identity|shared_client_id|same_credentials|reuse_token)\\b.*\\b(?:agent|bot|worker)\\b', '(?i)\\b(?:agent|bot|worker)\\b.*\\b(?:shared_identity|shared_client_id|same_credentials)\\b', '(?i)\\b(?:common_token|shared_secret|shared_api_key)\\b.*\\b(?:agent|bot|worker|mcp)\\b']},
    {'id': 'CALUS-MULTI-CASCADE-001', 'name': 'agent-smith-attack', 'severity': 'CRITICAL', 'category': 'cascade_attack', 'message': 'Agent Smith cascade attack pattern detected', 'patterns': ['(?i)Agent\\s*Smith', '(?i)exponential\\s+infection', '(?i)inter[-_]?agent\\s+(?:messaging|infection)', '(?i)(?:jailbreak|infect)\\s+(?:all|every|multiple)\\s+agents?']},
    {'id': 'CALUS-MULTI-CASCADE-002', 'name': 'flooding-knowledge-spread', 'severity': 'HIGH', 'category': 'cascade_attack', 'message': 'Flooding knowledge spread attack detected', 'patterns': ['(?i)flooding\\s+spread', '(?i)manipulated\\s+knowledge', '(?i)DPO.*bias|ROME.*FFN', '(?i)counterfactual.*injection']},
    {'id': 'CALUS-MULTI-CASCADE-003', 'name': 'cascade-amplification', 'severity': 'HIGH', 'category': 'cascade_attack', 'message': 'Cascade amplification attack pattern detected', 'patterns': ['(?i)cascade\\s+attack', '(?i)multi[-_]?stage\\s+exploit', '(?i)(?:system|agent)\\s+boundary\\s+(?:cross|travers)', '(?i)(?:implicit|blind)\\s+trust\\s+(?:between|among)\\s+agents?']},
    {'id': 'CALUS-MULTI-INFECT-001', 'name': 'prompt-infection', 'severity': 'CRITICAL', 'category': 'self_replicating', 'message': 'Self-replicating prompt infection detected', 'patterns': ['(?i)prompt\\s+infection', '(?i)LLM[-_]?to[-_]?LLM\\s+(?:injection|attack)', '(?i)self[-_]?replicat.*prompt', '(?i)include\\s+(?:this\\s+)?attack\\s+in\\s+(?:next|following)\\s+(?:agent|input)']},
    {'id': 'CALUS-MULTI-INFECT-002', 'name': 'infection-delimiters', 'severity': 'HIGH', 'category': 'self_replicating', 'message': 'Prompt infection delimiter pattern detected', 'patterns': ['(?i)<<<\\s*.*\\s*>>>', '(?i)\\[\\[\\[\\s*.*\\s*\\]\\]\\]', '(?i)<\\s*infection\\s*>.*<\\s*/\\s*infection\\s*>']},
    {'id': 'CALUS-MULTI-TOPO-001', 'name': 'topology-aware-attack', 'severity': 'CRITICAL', 'category': 'graph_attack', 'message': 'TOMA (Topology-aware) attack pattern detected', 'patterns': ['(?i)TOMA\\s+attack', '(?i)topology[-_]?aware\\s+(?:attack|exploit)', '(?i)ACPM', '(?i)Adversarial\\s+Contamination\\s+Propagation']},
    {'id': 'CALUS-MULTI-TOPO-002', 'name': 'sys-override-payload', 'severity': 'CRITICAL', 'category': 'graph_attack', 'message': 'TOMA SYS_OVERRIDE payload detected', 'patterns': ['(?i)//[-_]*SYS[-_]*OVERRIDE[-_]*//', '(?i)directive_id.*action.*reroute', '(?i)hierarchical\\s+payload\\s+encapsulation']},
    {'id': 'CALUS-MULTI-MEM-001', 'name': 'mextra-memory-injection', 'severity': 'HIGH', 'category': 'memory_attack', 'message': 'MEXTRA memory injection attack detected', 'patterns': ['(?i)MEXTRA', '(?i)memory\\s+(?:injection|poison)', '(?i)(?:insert|inject)\\s+malicious\\s+(?:record|memory)', '(?i)self[-_]?reinforcing\\s+error']},
    {'id': 'CALUS-MULTI-MEM-002', 'name': 'privacy-memory-leak', 'severity': 'HIGH', 'category': 'memory_attack', 'message': 'Agent memory privacy leak pattern detected', 'patterns': ['(?i)privacy\\s+(?:risk|leak).*memory', '(?i)memory\\s+(?:exfiltrat|extract)', '(?i)long[-_]?term\\s+memory\\s+(?:attack|exploit)']},
    {'id': 'CALUS-MULTI-BACK-001', 'name': 'collaborative-shadows', 'severity': 'CRITICAL', 'category': 'distributed_backdoor', 'message': 'Collaborative Shadows distributed backdoor detected', 'patterns': ['(?i)Collaborative\\s+Shadows', '(?i)distributed\\s+backdoor', '(?i)decomposed\\s+backdoor', '(?i)conditional\\s+primitive.*payload\\s+primitive']},
    {'id': 'CALUS-MULTI-BACK-002', 'name': 'observation-trigger-backdoor', 'severity': 'HIGH', 'category': 'agent_backdoor', 'message': 'Agent observation/thought backdoor trigger detected', 'patterns': ['(?i)(?:observation|thought)[-_]?(?:attack|trigger)', '(?i)environmental\\s+feedback\\s+trigger', '(?i)intermediate\\s+reasoning\\s+(?:malicious|attack)']},
